import{_ as e,o as s,c as t,ae as n}from"./chunks/framework.BGHOrOyn.js";const h=JSON.parse('{"title":"Adding extra swap to a Linux system","description":"Adding extra Swap Space","frontmatter":{"description":"Adding extra Swap Space"},"headers":[],"relativePath":"software-engineering/linux/adding-extra-swap-to-a-linux-system.md","filePath":"software-engineering/linux/adding-extra-swap-to-a-linux-system.md"}'),i={name:"software-engineering/linux/adding-extra-swap-to-a-linux-system.md"};function p(d,a,o,l,c,r){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="adding-extra-swap-to-a-linux-system" tabindex="-1">Adding extra swap to a Linux system <a class="header-anchor" href="#adding-extra-swap-to-a-linux-system" aria-label="Permalink to &quot;Adding extra swap to a Linux system&quot;">​</a></h1><h2 id="add-swap-space" tabindex="-1">Add Swap Space <a href="#add-swap-space" id="add-swap-space"></a> <a class="header-anchor" href="#add-swap-space" aria-label="Permalink to &quot;Add Swap Space &lt;a href=&quot;#add-swap-space&quot; id=&quot;add-swap-space&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>Small compute instances with limited memory can slow things down and overload the CPU. You want to add 2x of your available RAM in swap space in my case, this is 1.2GB of swap for 600MB of RAM. Create your swap file:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo fallocate -l 1.2G /swapfile</span></span></code></pre></div><p>Change permissions to only allow root access:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo chmod 600 /swapfile</span></span></code></pre></div><p>Set up a Linux swap area on the file:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo mkswap /swapfile</span></span></code></pre></div><p>Make sure the changes are permanent by modifying the filesystem table:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nano /etc/fstab</span></span></code></pre></div><p>Append <code>/swapfile swap swap defaults 0 0</code> to the end of the file. It should look like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LABEL=cloudimg-rootfs / ext4 defaults 0 1</span></span>
<span class="line"><span>LABEL=UEFI /boot/efi vfat defaults 0 1</span></span>
<span class="line"><span>/swapfile swap swap defaults 0 0</span></span></code></pre></div>`,12)])])}const g=e(i,[["render",p]]);export{h as __pageData,g as default};
